def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 1, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    priority += val * np.sin(ratio * b / (a + 2))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.15)) ** 1.7
            for c in range(1, 5):
                priority += (np.log1p(ratio) ** c) * np.tanh(ratio / (c + 1))
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    temp = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 0.7)
                    priority += np.tanh(temp) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if i % 2 == 0:
                for k in range(1, 6):
                    priority += np.sin(k * ratio * i) * (ratio - 4) ** k / (k + 1)
            else:
                for k in range(1, 6):
                    priority -= np.cos(k * ratio * i) * (ratio - 4) ** k / (k + 1)
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 1.2)
            priority = (s * np.sin(6.5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 1.7
            for m in range(1, 5):
                priority += np.cos(m * ratio * i) * ((ratio - 2) ** m) / m
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.2)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 4.5
            else:
                penalty = np.cos(22 * ratio) * 3.0
            priority = s + penalty + np.exp(-1.7 / (ratio + 0.08))
            for o in range(1, 6):
                priority += np.sin(o * ratio * i) * ((ratio - 1) ** o) / (o + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2.0) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.3) * 0.8
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 2.8) * np.cos(k * ratio * 2.2)
            priority = s + 1.2 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.0
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.3) * 3.5
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0)
            priority = s + 2.5 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.65:
            priority += np.log1p(item ** 2.2 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-3.5 * ratio) * 4.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        for extra in range(1, 3):
            priority += (np.sin(ratio * (i + extra) * 0.5) - np.cos(ratio * (i + extra) * 0.7)) * 0.25
        if priority < 0:
            priority = abs(priority) * 0.9
        else:
            priority *= 1.1
        priorities[i] = priority
    return priorities
